class Solution:
    def __init__(self, n: int, blacklist: List[int]):
        self.m = n - len(blacklist)
        self.mp = {}
        bl = set(blacklist)
        for x in blacklist:
            if x < self.m:
                while self.m in bl or self.m in self.mp:
                    self.m += 1
                self.mp[x] = self.m
                self.m += 1
    def pick(self) -> int:
        x = random.randint(0, self.m - 1)
        return self.mp.get(x, x)

