class Solution {
    int m;
    unordered_map<int,int> mp;
public:
    Solution(int n, vector<int>& blacklist) {
        unordered_set<int> bl(blacklist.begin(), blacklist.end());
        m = n - (int)blacklist.size();
        for (int x : blacklist) {
            if (x < m) {
                while (bl.count(m) || mp.count(m)) m++;
                mp[x] = m++;
            }
        }
    }
    int pick() {
        int x = rand() % m;
        return mp.count(x) ? mp[x] : x;
    }
};

